const KBANK_API = 'https://m.kbanknow.com';

/* ────── Types ────── */
interface NoticeFile {
  atchFileNm: string;
  atchFileMgmtNbr: string;
  atchFileSeqNbr: string;
}
interface NoticeDetail {
  ttl: string;
  frstRgstDttm: string;
  cntnt: string;
  fileList?: NoticeFile[];
}

/* ────── Utils ────── */
function formatDate(raw: string): string {
  if (!raw) return '';
  const s = String(raw);
  if (s.length === 8) return `${s.slice(0,4)}.${s.slice(4,6)}.${s.slice(6,8)}`;
  return s;
}

function decode(s?: string): string {
  if (!s) return '';
  try { return decodeURIComponent(s).replace(/\+/g, ' '); } catch { return s; }
}

/* ────── API ────── */
async function fetchBsntDetail(pbntId: string): Promise<NoticeDetail | null> {
  try {
    const res = await fetch(`${KBANK_API}/ib20/act/HOMBKI0201010200A`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ pbntId }),
    });
    const data = await res.json();
    const body = data._msg_?._body_;
    if (!body) return null;
    return {
      ttl: decode(body.ttl),
      frstRgstDttm: body.frstRgstDttm || '',
      cntnt: decode(body.cntnt),
      fileList: (body.fileList || []).map((f: NoticeFile) => ({
        ...f,
        atchFileNm: decode(f.atchFileNm),
      })),
    };
  } catch {
    return null;
  }
}

