/* ════════════════════════════
   Main Page
════════════════════════════ */
export default function NoticeViewPage() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const num = searchParams.get('num') || '';
  const [detail, setDetail] = useState<NoticeDetail | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!num) return;
    fetchBsntDetail(num).then(d => {
      setDetail(d);
      setLoading(false);
      setTimeout(() => window.scrollTo(0, 0), 100);
    });
  }, [num]);

  const handleDownload = (mgmtNbr: string, seqNbr: string, fileName: string) => {
    const url = `${KBANK_API}/ib20/fil/download?atchFileMgmtNbr=${mgmtNbr}&atchFileSeqNbr=${seqNbr}&atchFileNm=${encodeURIComponent(fileName)}`;
    window.open(url, '_blank');
  };

  return (
    <PageWrap>
      <Header isDark={false} isWhiteBg={true} />

      {/* Page Title */}
      <TopContentsWrapper>
        <TitleBar>
          <TitleTextWrap>
            <PageTitle>사업공고</PageTitle>
          </TitleTextWrap>
        </TitleBar>

        {/* Notice meta */}
        {loading ? (
          <SkeletonWrap>
            <SkeletonLine w="80%" />
            <SkeletonLine w="40%" />
          </SkeletonWrap>
        ) : detail ? (
          <BoardListWrap>
            <AlignBox1>
              <LeftContentsBox>
                <AlignBox2>
                  <TitleBox>
                    <NoticeTitle>{detail.ttl}</NoticeTitle>
                    <NoticeDate>{formatDate(detail.frstRgstDttm)}</NoticeDate>
                  </TitleBox>
                </AlignBox2>
              </LeftContentsBox>
            </AlignBox1>
          </BoardListWrap>
        ) : null}
      </TopContentsWrapper>

      <Divider />

      {/* File attachments */}
      {!loading && detail?.fileList && detail.fileList.length > 0 && (
        <>
          <FileListWrap>
            {detail.fileList.map((file, i) => (
              <FileItem key={i} onClick={() => handleDownload(file.atchFileMgmtNbr, file.atchFileSeqNbr, file.atchFileNm)}>
                <FileIconWrap><DownloadIcon /></FileIconWrap>
                <FileName>{file.atchFileNm}</FileName>
              </FileItem>
            ))}
          </FileListWrap>
          <Divider />
        </>
      )}

      {/* HTML Content */}
      {loading ? (
        <SkeletonWrap>
          {[100, 80, 90, 60, 75].map((w, i) => <SkeletonLine key={i} w={`${w}%`} />)}
        </SkeletonWrap>
      ) : detail ? (
        <ContentWrap dangerouslySetInnerHTML={{ __html: detail.cntnt || '<p style="color:#67748e">내용이 없습니다.</p>' }} />
      ) : (
        <ContentWrap><p style={{ color: '#67748e' }}>공지사항을 불러오지 못했습니다.</p></ContentWrap>
      )}

      {/* Back button */}
      <BackBtn onClick={() => navigate('/notice/list')}>목록 돌아가기</BackBtn>

      <FooterPad />
    </PageWrap>
  );
}
