/**
 * K-bank API service
 * 실제 케이뱅크 API를 호출하고, CORS 등으로 실패 시 bundled mock data로 fallback
 */

const KBANK_BASE = 'https://m.kbanknow.com';

export interface MwInfoItem {
  IDX: number;
  DS_CD: string;
  MAIN_DESC: string;
  SUB_DESC: string;
  IMG_PATH: string;
  LNK_URL: string;
  START_DT: string;
  END_DT: string;
  USE_YN: string;
  SQNC: string;
}

export interface StoryItem {
  id: number;
  title: string;
  subDesc: string;
  imgUrl: string;
  linkUrl: string;
  dsCode: string;
}

/** ArticleItem (스토리 목록 페이지용 - dsCode 포함) */
export interface ArticleItem {
  id: number;
  title: string;
  subDesc: string;
  imgUrl: string;
  linkUrl: string;
  dsCode: string;
}

/** URL-encoded 문자열 디코딩 (+ → 공백, %XX → 문자) */
function decodeField(val: string): string {
  try {
    return decodeURIComponent(val.replace(/\+/g, ' '));
  } catch {
    return val;
  }
}

/** MwInfoItem → StoryItem / ArticleItem 공통 변환 */
function toItem(item: MwInfoItem): StoryItem {
  const imgPath = decodeField(item.IMG_PATH);
  return {
    id: item.IDX,
    title: decodeField(item.MAIN_DESC),
    subDesc: decodeField(item.SUB_DESC),
    imgUrl: `${KBANK_BASE}${imgPath}`,
    linkUrl: item.LNK_URL,
    dsCode: item.DS_CD,
  };
}

/**
 * 케이뱅크 홈 뉴스/스토리 API 호출
 * DS_CD === '3' 인 항목만 반환 (홈 스와이퍼 스토리)
 */
export async function getMwStories(): Promise<StoryItem[]> {
  try {
    const res = await fetch(`${KBANK_BASE}/ib20/act/MWBMAN0000000400A`, {
      headers: {
        Referer: `${KBANK_BASE}/mw/mw-home/home/`,
      },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    const items: MwInfoItem[] = data?._msg_?._body_?.mwInfo ?? [];
    const stories = items.filter((x) => x.DS_CD === '3').map(toItem);
    if (stories.length > 0) return stories;
    throw new Error('empty result');
  } catch (err) {
    console.warn('[kbankApi] getMwStories fallback to mock:', err);
    return STORY_MOCK_DATA;
  }
}

/**
 * 전체 아티클 조회 (스토리 목록 페이지용)
 * DS_CD 필터 없이 전체 반환 (1: 스토리, 2: 테크, 3: 주요뉴스)
 */
export async function getMwAllArticles(): Promise<ArticleItem[]> {
  try {
    const res = await fetch(`${KBANK_BASE}/ib20/act/MWBMAN0000000400A`, {
      headers: {
        Referer: `${KBANK_BASE}/mw/article/list`,
      },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    const items: MwInfoItem[] = data?._msg_?._body_?.mwInfo ?? [];
    if (items.length > 0) return items.map(toItem);
    throw new Error('empty result');
  } catch (err) {
    console.warn('[kbankApi] getMwAllArticles fallback to mock:', err);
    return ARTICLE_MOCK_DATA;
  }
}

