/* imgShape:
   - 카드(Card)    → 'rectAngle'  (radius25=0.125rem)
   - 투자(Invm)    → 'circle'     (50%, showImgBorder=true)
   - 서비스(Svr)   → 'circle'     (50%)
   - 예적금/대출/사장님 → imgUrl='' → 이미지 렌더링 안 함
*/
interface ProductItem {
  id: string;
  name: string;
  subTitle: string;
  imgUrl: string;          // '' → 이미지 없음
  imgShape?: 'circle' | 'rectAngle' | 'squarecle';
  showImgBorder?: boolean;
  menuId: string;
  categoryNm: string;
  showBadge?: boolean;
  badge1?: string;   /* pdListBdg3 neutral (보라) */
  badge2?: string;   /* pdListBdg4 accent (파랑) */
  leftDesc1?: string;
  num1?: string;
  leftDesc2?: string;
  num2?: string;
  isLoan?: boolean;
}

