/* ═══════════════════════════
   API 파싱
═══════════════════════════ */
function dec(v = '') {
  try { return decodeURIComponent(v.replace(/\+/g, ' ')); } catch { return v; }
}

async function fetchProducts(): Promise<Record<string, ProductItem[]>> {
  try {
    const res = await fetch(`${KBANK}/ib20/act/PBKMAN0000003101A?from=mobileWeb`, {
      headers: { Referer: `${KBANK}/mw/product/list` },
    });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    const body = data?._msg_?._body_;
    if (!body?.pdMaps) throw new Error('no pdMaps');

    const { pdMaps, ceoTabList = [] } = body;
    const result: Record<string, ProductItem[]> = {
      deposit:[], loan:[], card:[], invest:[], service:[], biz:[],
    };

    /* 원본 탭별 이미지 규칙:
       100(예적금)/200(대출): imgSrc 전달 안 함 → imgUrl=''
       300(카드): rprsImgFileNm, shape='rectAngle'
       400(투자): rprsImgFileNm2, shape='circle', showImgBorder=true
       600(서비스): rprsImgFileNm2, shape='circle' */
    type TabCfg = { key:string; isLoan:boolean; imgField:string; imgShape?:ProductItem['imgShape']; showImgBorder?:boolean };
    const tabMap: Record<number, TabCfg> = {
      100: { key:'deposit', isLoan:false, imgField:'' },            // 이미지 없음
      200: { key:'loan',    isLoan:true,  imgField:'' },            // 이미지 없음
      300: { key:'card',    isLoan:false, imgField:'rprsImgFileNm',  imgShape:'rectAngle' },
      400: { key:'invest',  isLoan:false, imgField:'rprsImgFileNm2', imgShape:'circle', showImgBorder:true },
      600: { key:'service', isLoan:false, imgField:'rprsImgFileNm2', imgShape:'circle' },
    };

    for (const [pdDtlId, cfg] of Object.entries(tabMap)) {
      const items = pdMaps[Number(pdDtlId)] ?? [];
      items.forEach((item: any) => {
        const d = (k: string) => dec(dec(item[k] || ''));
        const imgPath = cfg.imgField ? d(cfg.imgField) : '';
        /* 대출 금리 범위 */
        const lowRate  = d('rate');
        const highRate = d('maxIntrInfo');
        const rateStr  = cfg.isLoan && lowRate && highRate && lowRate !== highRate
          ? `${lowRate}` : lowRate || highRate || undefined;
        const rateHigh = cfg.isLoan && lowRate && highRate && lowRate !== highRate ? highRate : undefined;
        const bdg1 = d('pdListBdg1');
        const bdg3 = d('pdListBdg3');  /* neutral (보라) */
        const bdg4 = d('pdListBdg4');  /* accent (파랑)  */
        result[cfg.key].push({
          id:             d('fnclPdId') || String(Math.random()),
          name:           d('chnlPdNm'),
          subTitle:       d('mainTit'),
          imgUrl:         imgPath ? `${KBANK}${imgPath}` : '',
          imgShape:       cfg.imgShape,
          showImgBorder:  cfg.showImgBorder,
          menuId:         d('fnclPdMenuId'),
          categoryNm:     d('fnclPdTpCdNm'),
          isLoan:         cfg.isLoan,
          showBadge:      bdg1 === 'NEW',
          badge1:         bdg3 || undefined,
          badge2:         bdg4 || undefined,
          leftDesc1:      (cfg.isLoan ? d('intrTppoCntnt') : d('maxIntrDesc')) || (rateStr ? '연' : undefined),
          num1:           rateStr,
          leftDesc2:      rateHigh ? '~' : undefined,
          num2:           rateHigh,
        });
      });
    }

    /* 사장님 탭(ceoTabList): 3그룹, ceoTabCategoryTitles 기준 카테고리 */
    const ceoTitles: string[] = (body.ceoTabCategoryTitles ?? []).map((t: string) =>
      dec(dec(t))
    );
    ceoTabList.forEach((group: any[], gi: number) => {
      const catTitle = ceoTitles[gi] || '';
      (Array.isArray(group) ? group : [group]).forEach((item: any) => {
      const d = (k: string) => dec(dec(item[k] || ''));
      const isL = d('fnclPdDsCdNm') === '대출' || d('fnclPdTpCdNm') === '대출';
      const lowRate  = d('rate');
      const highRate = d('maxIntrInfo');
      const hasRange = isL && lowRate && highRate && lowRate !== highRate;
      const bdg1 = d('pdListBdg1');
      const bdg3 = d('pdListBdg3');
      const bdg4 = d('pdListBdg4');
      const imgPath = d('ceoRprsImgFileNm') || d('rprsImgFileNm2') || d('rprsImgFileNm');
      result.biz.push({
        id:         d('fnclPdId') || String(Math.random()),
        name:       d('chnlPdNm'),
        subTitle:   d('mainTit'),
        imgUrl:     imgPath ? `${KBANK}${imgPath}` : '',
        imgShape:   imgPath ? 'circle' : undefined,
        menuId:     d('fnclPdMenuId'),
        categoryNm: catTitle || d('fnclPdTpCdNm'),
        isLoan:     isL,
        showBadge:  bdg1 === 'NEW',
        badge1:     bdg3 || undefined,
        badge2:     bdg4 || undefined,
        leftDesc1:  lowRate ? d('intrTppoCntnt') || '연' : undefined,
        num1:       lowRate || undefined,
        leftDesc2:  hasRange ? '~' : undefined,
        num2:       hasRange ? highRate : undefined,
      });
      });
    });

    const hasData = Object.values(result).some(a => a.length > 0);
    if (!hasData) throw new Error('empty');
    return result;
  } catch (err) {
    console.warn('[ProductListPage] API fallback:', err);
    return MOCK;
  }
}

/* ═══════════════════════════
   상품 아이템 컴포넌트
═══════════════════════════ */
function ProductItem_({ item, showDivider, onClick }: {
  item: ProductItem; showDivider: boolean; onClick: () => void;
}) {
  const [imgFailed, setImgFailed] = useState(false);
  const showImg = !!item.imgUrl && !imgFailed;

  return (
    <>
      <ProductContainer onClick={onClick}>
        <ItemTopPad />
        <ItemBox>
          {/* 썸네일 — 원본 탭별:
              예적금/대출/사장님: imgUrl='' → 렌더링 안 함
              카드: shape='rectAngle', 투자: shape='circle'+border, 서비스: shape='circle' */}
          {item.imgUrl && (
            <ImgBox shape={item.imgShape} showBorder={item.showImgBorder}>
              {showImg ? (
                <Thumbnail
                  src={item.imgUrl}
                  alt={item.name}
                  onError={() => setImgFailed(true)}
                />
              ) : (
                <div style={{
                  width: item.imgShape === 'circle' ? '60%' : '70%',
                  height: item.imgShape === 'circle' ? '60%' : '70%',
                  background: '#dde2ec',
                  borderRadius: item.imgShape === 'circle' ? '50%' : '0.125rem',
                }} />
              )}
            </ImgBox>
          )}

          <ListBox>
            {/* ListLeft */}
            <ListLeft>
              <NameRow>
                <ProductName>{item.name}</ProductName>
                {item.showBadge && <BadgeN>N</BadgeN>}
                {item.badge1 && <BadgeNeutral>{item.badge1}</BadgeNeutral>}
                {item.badge2 && <BadgeAccent>{item.badge2}</BadgeAccent>}
              </NameRow>
              {item.subTitle && <SubTitle>{item.subTitle}</SubTitle>}
            </ListLeft>

            {/* ListRight (금리/한도)
                비대출: label=C2(0.75rem fw400), value=L3(0.9375rem fw700) textActiveTertiary=#2539e9
                대출:   label=L4(0.875rem fw400), value=L4(0.875rem fw700) textActiveTertiary=#2539e9 */}
            {item.num1 && (
              <ListRight>
                <RateRow>
                  {item.leftDesc1 && <RateLabel isLoan={item.isLoan}>{item.leftDesc1}</RateLabel>}
                  <RateValue isLoan={item.isLoan}>{item.num1}</RateValue>
                </RateRow>
                {item.num2 && (
                  <RateRow>
                    {item.leftDesc2 && <RateLabel isLoan={item.isLoan}>{item.leftDesc2}</RateLabel>}
                    <RateValue isLoan={item.isLoan}>{item.num2}</RateValue>
                  </RateRow>
                )}
              </ListRight>
            )}
          </ListBox>
        </ItemBox>
        <ItemBotPad />
      </ProductContainer>
      {showDivider && <Divider />}
    </>
  );
}

/* ═══════════════════════════
   탭 콘텐츠 (카테고리 그룹 → 아이템)
═══════════════════════════ */
function TabContent({ items, onClickItem }: {
  items: ProductItem[];
  onClickItem: (item: ProductItem) => void;
}) {
  if (items.length === 0) return <EmptyBox>상품 정보가 없습니다.</EmptyBox>;

  /* 카테고리별 그룹핑 (순서 유지) */
  const groups: { category: string; list: ProductItem[] }[] = [];
  items.forEach(item => {
    const last = groups[groups.length - 1];
    if (last && last.category === item.categoryNm) last.list.push(item);
    else groups.push({ category: item.categoryNm, list: [item] });
  });

  return (
    <ContentArea>
      {groups.map(({ category, list }) => (
        <div key={category}>
          {category && <CategoryTitle>{category}</CategoryTitle>}
          <ItemListWrapper>
            {list.map((item, idx) => (
              <ProductItem_
                key={item.id}
                item={item}
                showDivider={idx < list.length - 1}
                onClick={() => onClickItem(item)}
              />
            ))}
          </ItemListWrapper>
        </div>
      ))}
    </ContentArea>
  );
}

/* ═══════════════════════════
   메인
═══════════════════════════ */
function ProductListPage() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState(0);
  const [products, setProducts] = useState<Record<string, ProductItem[]>>(MOCK);
  const [loading, setLoading]   = useState(true);
  const chipRefs = useRef<(HTMLButtonElement | null)[]>([]);

  useEffect(() => {
    fetchProducts().then(data => { setProducts(data); setLoading(false); });
  }, []);

  useEffect(() => {
    chipRefs.current[activeTab]?.scrollIntoView({ behavior:'smooth', inline:'center', block:'nearest' });
  }, [activeTab]);

  const goProduct = (item: ProductItem) =>
    window.open(`${KBANK}/mw/ib20/mnu/${item.menuId}`, '_blank', 'noopener,noreferrer');

  const currentItems = products[TABS[activeTab].id] ?? [];

  return (
    <ThemeProvider theme={theme}>
      <GlobalStyle />
      <PageWrapper>
        {/* GNB 헤더 */}
        <Header isDark={false} isWhiteBg={true} />

        {/* 칩 탭 바 */}
        <ChipBar>
          <ChipScroll>
            {TABS.map((tab, idx) => (
              <Chip
                key={tab.id}
                active={activeTab === idx}
                ref={el => { chipRefs.current[idx] = el; }}
                onClick={() => setActiveTab(idx)}
              >
                {tab.label}
              </Chip>
            ))}
          </ChipScroll>
        </ChipBar>

        {/* 탭 콘텐츠 */}
        {loading ? (
          <EmptyBox>불러오는 중...</EmptyBox>
        ) : (
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.18 }}
              style={{ flex: 1 }}
            >
              <TabContent items={currentItems} onClickItem={goProduct} />
            </motion.div>
          </AnimatePresence>
        )}
      </PageWrapper>
    </ThemeProvider>
  );
}

export default ProductListPage;
