/* ────── 날짜 D-Day 계산 ────── */
function calcDday(endDttm: string): string | null {
  if (!endDttm) return null;
  const y = +endDttm.slice(0,4), m = +endDttm.slice(4,6)-1, d = +endDttm.slice(6,8);
  const diff = Math.ceil((new Date(y,m,d).getTime() - Date.now()) / 86400000);
  if (diff < 0) return null;
  if (diff === 0) return 'D-day';
  return `D-${diff}`;
}

