interface BenefitItemProps {
  imgSrc: string;
  type: 'icon' | 'row';
  title: string;
  subTitle?: string;
  descript?: string;
  showDivider: boolean;
  isNew?: boolean;
  countdown?: string | null;
  onClick: () => void;
}
const BenefitItem = ({ imgSrc, type, title, subTitle, descript, showDivider, isNew, countdown, onClick }: BenefitItemProps) => (
  <ListItemWrap onClick={onClick}>
    <ListItemPad />
    <ListItemRow>
      <ListItemThumb>
        <ListItemThumbImg
          src={imgSrc}
          alt={title}
          onError={(e) => { (e.target as HTMLImageElement).style.display = 'none'; }}
        />
      </ListItemThumb>
      <ListItemText>
        <ListItemTitleRow>
          <ListItemTitle>{title}</ListItemTitle>
          {isNew && <NewBadge>N</NewBadge>}
          {countdown && !isNew && <DdayBadge>{countdown}</DdayBadge>}
        </ListItemTitleRow>
        <ListItemSub>{type === 'icon' ? subTitle : descript}</ListItemSub>
      </ListItemText>
      {type === 'icon' && (
        <ListItemChevron>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
            <path d="M9 18l6-6-6-6" stroke="#c8d2e4" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </ListItemChevron>
      )}
    </ListItemRow>
    <ListItemPad />
    {showDivider && <ListDivider />}
  </ListItemWrap>
);

