/* ════════════════════════════
   API 호출
════════════════════════════ */
async function fetchBenefitData() {
  const res = await fetch(`${KBANK_API}/ib20/act/MWBMAN000001A200A`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'Referer': `${KBANK_API}/mw/benefit/list`,
    },
    body: JSON.stringify({ command: 'GET_EVENT_LIST_INFO' }),
  });
  if (!res.ok) throw new Error('API error');
  const json = await res.json();
  const body = json._msg_._body_;
  // decode double-encoded fields
  const events: ProgressEvent[] = Object.values(body.progressEventList as Record<string, ProgressEvent>)
    .map((ev: ProgressEvent) => ({
      ...ev,
      TTL: decodeURIComponent(ev.TTL),
      TTL_BNFS: decodeURIComponent(ev.TTL_BNFS),
      TTL_CND: ev.TTL_CND ? decodeURIComponent(ev.TTL_CND) : null,
    }));
  return {
    events,
    rewardServiceOrderList: body.rewardServiceOrderList as RewardService[],
    categoryList: body.categoryList as Category[],
    popularMax: parseInt(body.popularEventCountMinMax?.max || '5'),
  };
}

/* ════════════════════════════
   메인 컴포넌트
════════════════════════════ */
const MOCK_REWARD_ORDER: RewardService[] = [
  { id: 'gettingAllowance', title: '용돈받기', subTitle: '매일 받을 수 있어요', order: 1 },
  { id: 'inAndOutReward',   title: '입출금리워드', subTitle: '최대 현금 1천원', order: 1 },
  { id: 'aiQuizChallenge',  title: 'AI 퀴즈 챌린지', subTitle: '매주 열리는 상금', order: 1 },
  { id: 'moneyTree',        title: '돈나무키우기', subTitle: '매일 현금이 자라나요', order: 2 },
  { id: 'buttonClick',      title: '버튼 누르고', subTitle: '최대 7원 받기', order: 50 },
];
const MOCK_CATS: Category[] = [
  { id: 'FLRG02', name: '상품가입' },
  { id: 'FLRG01', name: '정부지원금' },
  { id: 'FLRG03', name: '결제혜택' },
  { id: 'FLRG04', name: '고객참여' },
];

export default function BenefitListPage() {
  const navigate = useNavigate();
  const [rewardServices, setRewardServices] = useState<Array<typeof REWARD_STATIC[string] & { title: string; subTitle: string }>>([]);
  const [allEvents, setAllEvents] = useState<ProgressEvent[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [popularEvents, setPopularEvents] = useState<ProgressEvent[]>([]);
  const [activeChip, setActiveChip] = useState(0);
  const [cardVisible, setCardVisible] = useState<boolean[]>([]);
  const catRefs = useRef<Record<string, HTMLDivElement | null>>({});
  const carouselRef = useRef<HTMLDivElement>(null);

  const buildRewardServices = useCallback((orderList: RewardService[]) => {
    const validItems = orderList.filter(item => item.id in REWARD_STATIC);
    const sorted = [...validItems].sort((a, b) => a.order === b.order ? Math.random() - 0.5 : a.order - b.order);
    return sorted.map(item => ({
      ...REWARD_STATIC[item.id],
      title: item.title,
      subTitle: item.subTitle,
      id: item.id,
    }));
  }, []);

  useEffect(() => {
    fetchBenefitData()
      .then(({ events, rewardServiceOrderList, categoryList, popularMax }) => {
        setAllEvents(events);
        // popular: PRMRY_EVNT_YN=Y, sorted by PRMRY_EVNT_NTH, up to max
        const popular = events
          .filter(e => e.PRMRY_EVNT_YN === 'Y')
          .sort((a, b) => parseInt(a.PRMRY_EVNT_NTH) - parseInt(b.PRMRY_EVNT_NTH))
          .slice(0, popularMax);
        setPopularEvents(popular);
        // categories (only those with at least 1 event)
        const usedIds = new Set(events.map(e => e.EVNT_CATE_DS_CD));
        setCategories(categoryList.filter(c => usedIds.has(c.id)));
        // reward services
            const svcs = buildRewardServices(rewardServiceOrderList) as any;
        setRewardServices(svcs);
        setCardVisible(svcs.map((_: any, i: number) => i <= 1)); // 처음 2개 즉시 animate
      })
      .catch(() => {
        // API 실패 → mock 데이터로 fallback
        console.warn('[BenefitListPage] API fallback: using mock data');
        const popular = MOCK_EVENTS
          .filter(e => e.PRMRY_EVNT_YN === 'Y')
          .sort((a, b) => parseInt(a.PRMRY_EVNT_NTH) - parseInt(b.PRMRY_EVNT_NTH))
          .slice(0, 5);
        setPopularEvents(popular);
        setAllEvents(MOCK_EVENTS);
        const usedIds = new Set(MOCK_EVENTS.map(e => e.EVNT_CATE_DS_CD));
        setCategories(MOCK_CATS.filter(c => usedIds.has(c.id)));
        const mockSvcs = buildRewardServices(MOCK_REWARD_ORDER) as any;
        setRewardServices(mockSvcs);
        setCardVisible(mockSvcs.map((_: any, i: number) => i <= 1));
      });
  }, [buildRewardServices]);

  // 캐러셀 스크롤 시 카드 가시성 업데이트 (원본: Flicking onChanged)
  const handleCarouselScroll = useCallback(() => {
    const el = carouselRef.current;
    if (!el) return;
    const cardWidth = 9.25 * 16 + 0.6 * 16; // card + gap (approx)
    const currentIdx = Math.floor(el.scrollLeft / cardWidth);
    setCardVisible(prev => prev.map((v, i) => i <= currentIdx + 1 || v));
  }, []);

  const getEventsByCategory = useCallback((catId: string) => {
    const popularIds = new Set(popularEvents.map(e => e.EVNT_ID));
    return allEvents
      .filter(e => e.EVNT_CATE_DS_CD === catId && !popularIds.has(e.EVNT_ID))
      .sort((a, b) => parseInt(a.EVNT_NTH) - parseInt(b.EVNT_NTH));
  }, [allEvents, popularEvents]);

  const handleChipClick = (idx: number) => {
    setActiveChip(idx);
    const cat = categories[idx];
    if (cat && catRefs.current[cat.name]) {
      const el = catRefs.current[cat.name]!;
      const top = el.getBoundingClientRect().top + window.scrollY - 7 * 16; // ~7rem offset
      window.scrollTo({ top, behavior: 'smooth' });
    }
  };

  const goToView = (evntId: string) => {
    navigate(`/benefit/view?num=${evntId}`);
  };

  return (
    <>
      <Header isDark={false} isWhiteBg={true} />
      <PageWrap>
        <ContentsBox>

          {/* ── 1. 리워드 서비스 캐러셀 ── */}
          <CarouselSection>
            <SectionHead>
              <SectionLabel>매일매일 돈 되는 습관</SectionLabel>
              <SectionTitle>다양한 리워드를 만나보세요</SectionTitle>
            </SectionHead>
            <CarouselArea ref={carouselRef} onScroll={handleCarouselScroll}>
              {rewardServices.map((svc: any, idx: number) => (
                <CardSlot key={svc.id || idx} isFirst={idx === 0} isLast={idx === rewardServices.length - 1}>
                  <BenefitCard bg={svc.bg}>
                    <CardThumb>
                      {/* 원본: framer-motion spring y:"50%"→0, stiffness:500, damping:15 */}
                      <motion.div
                        initial={{ y: '50%', opacity: 1, scale: 1 }}
                        animate={cardVisible[idx] ? { y: 0, opacity: 1, scale: 1 } : {}}
                        transition={{ duration: 0.2, type: 'spring', stiffness: 500, damping: 15 }}
                      >
                        <ThumbImg
                          src={svc.imgSrc}
                          alt={svc.title}
                          onError={(e) => { (e.target as HTMLImageElement).style.display = 'none'; }}
                        />
                      </motion.div>
                    </CardThumb>
                    <CardContent>
                      <CardTextBox>
                        <CardTitle>{svc.title}</CardTitle>
                        <CardSubTitle>{svc.subTitle}</CardSubTitle>
                      </CardTextBox>
                      <CardBtn onClick={(e) => { e.stopPropagation(); }}>
                        {svc.buttonName}
                      </CardBtn>
                    </CardContent>
                  </BenefitCard>
                </CardSlot>
              ))}
            </CarouselArea>
          </CarouselSection>

          {/* ── 2. 케이뱅크 인기혜택 ── */}
          {popularEvents.length > 0 && (
            <PopularSection>
              <SectionHead style={{ padding: 0 }}>
                <SectionLabel>케이뱅크 인기혜택</SectionLabel>
                <SectionTitle>많은 사람들이 보고 있어요</SectionTitle>
              </SectionHead>
              <EventCardBox>
                {popularEvents.map((ev, idx) => (
                  <BenefitItem
                    key={ev.EVNT_ID}
                    imgSrc={`${KBANK_RES}/not/${ev.ICON_FILE_NM}`}
                    type="icon"
                    title={ev.TTL}
                    subTitle={ev.TTL_BNFS}
                    showDivider={idx !== popularEvents.length - 1}
                    isNew={ev.IS_NEW === 'true'}
                    countdown={ev.SUPPL_CNTNT === 'COUNTDOWN' ? calcDday(ev.END_DTTM) : null}
                    onClick={() => goToView(ev.EVNT_ID)}
                  />
                ))}
              </EventCardBox>
            </PopularSection>
          )}

          {/* ── 3. 케이뱅크 맞춤혜택 ── */}
          <CustomSection>
            <SectionHead>
              <SectionLabel>케이뱅크 맞춤혜택</SectionLabel>
              <SectionTitle>딱 맞는 혜택을 찾아보세요</SectionTitle>
            </SectionHead>

            {/* 필터 칩 (sticky) */}
            {categories.length > 0 && (
              <Navi>
                <ChipScroll>
                  {categories.map((cat, idx) => (
                    <Chip
                      key={cat.id}
                      active={activeChip === idx}
                      onClick={() => handleChipClick(idx)}
                    >
                      {cat.name}
                    </Chip>
                  ))}
                </ChipScroll>
              </Navi>
            )}

            {/* 카테고리별 이벤트 목록 */}
            <CategoryList>
              {categories.map((cat, catIdx) => {
                const evs = getEventsByCategory(cat.id);
                if (evs.length === 0) return null;
                return (
                  <div key={cat.id}>
                    <CatTitle
                      id={cat.name}
                      ref={(el) => { catRefs.current[cat.name] = el; }}
                    >
                      <CatName>{cat.name}</CatName>
                      <CatCount>{evs.length}</CatCount>
                    </CatTitle>
                    {evs.map((ev, evIdx) => (
                      <BenefitItem
                        key={ev.EVNT_ID}
                        imgSrc={`${KBANK_RES}/not/${ev.ICON_FILE_NM}`}
                        type="row"
                        title={ev.TTL}
                        descript={ev.TTL_BNFS}
                        showDivider={evIdx !== evs.length - 1}
                        isNew={ev.IS_NEW === 'true'}
                        countdown={ev.SUPPL_CNTNT === 'COUNTDOWN' ? calcDday(ev.END_DTTM) : null}
                        onClick={() => goToView(ev.EVNT_ID)}
                      />
                    ))}
                  </div>
                );
              })}
            </CategoryList>
          </CustomSection>

        </ContentsBox>
        <PageFooter />
      </PageWrap>
    </>
  );
}
