const KBANK_API = 'https://m.kbanknow.com';
const COVER_IMG = 'https://m.kbanknow.com/mw/resource/images/comInrd/CoverImage06.png';

/* ────── Types ────── */
interface NoticeItem {
  pbntId: number;
  ttl: string;
  frstRgstDttm: string;
  bizDsCd?: number;
  cntnt?: string;
}

interface BsntItem {
  pbntId: number;
  ttl: string;
  frstRgstDttm: string;
}

/* ────── Utils ────── */
function formatDate(raw: string): string {
  if (!raw) return '';
  const s = String(raw);
  if (s.length === 8) return `${s.slice(0,4)}.${s.slice(4,6)}.${s.slice(6,8)}`;
  return s;
}

function decode(s?: string): string {
  if (!s) return '';
  try { return decodeURIComponent(s).replace(/\+/g, ' '); } catch { return s; }
}

/* ────── API ────── */
async function fetchNoticeList(page: number): Promise<{ list: NoticeItem[]; pageCount: number; totalCount: number }> {
  const res = await fetch(`${KBANK_API}/ib20/act/CMMNOT0100000100A`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ pbntDsCd: 'MGTNOT030000', pPageNum: page }),
  });
  const data = await res.json();
  return data._msg_._body_;
}

async function fetchNoticeDetail(pbntId: number): Promise<string> {
  const res = await fetch(`${KBANK_API}/ib20/act/CMMNOT0100000100A`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ pbntId, type: 'detail' }),
  });
  const data = await res.json();
  return decode(data._msg_?._body_?.cntnt || '');
}

async function fetchBsntList(page: number): Promise<{ list: BsntItem[]; pageCount: number }> {
  const res = await fetch(`${KBANK_API}/ib20/act/HOMBKI0302000100A`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ actionType: 'R', pPageNum: page }),
  });
  const data = await res.json();
  return data._msg_._body_;
}

