function ChevronSVG() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
      <path d="M4 6L8 10L12 6" stroke="#67748e" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  );
}

/* ────── 공지사항 탭 (Accordion) ────── */
function PbntTabList() {
  const [items, setItems] = useState<NoticeItem[]>([]);
  const [openStates, setOpenStates] = useState<boolean[]>([]);
  const [contents, setContents] = useState<string[]>([]);
  const [page, setPage] = useState(1);
  const [pageCount, setPageCount] = useState(1);
  const [loading, setLoading] = useState(true);
  const bottomRef = useRef<HTMLDivElement>(null);

  const loadMore = useCallback(async () => {
    if (page > pageCount) return;
    try {
      const data = await fetchNoticeList(page);
      const newItems = (data.list || []).map((it: NoticeItem) => ({
        ...it,
        ttl: decode(it.ttl),
      }));
      setItems(prev => [...prev, ...newItems]);
      setOpenStates(prev => [...prev, ...Array(newItems.length).fill(false)]);
      setContents(prev => [...prev, ...Array(newItems.length).fill('')]);
      setPageCount(parseInt(String(data.pageCount)));
      setPage(p => p + 1);
    } finally {
      setLoading(false);
    }
  }, [page, pageCount]);

  useEffect(() => { loadMore(); }, []); // eslint-disable-line

  useEffect(() => {
    if (loading) return;
    if (page > pageCount) return;
    const el = bottomRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) loadMore();
    }, { threshold: 1 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [bottomRef.current, loading, page, pageCount, loadMore]);

  const handleClick = async (pbntId: number, idx: number) => {
    const next = !openStates[idx];
    setOpenStates(prev => prev.map((s, i) => i === idx ? next : s));
    if (next && !contents[idx]) {
      const html = await fetchNoticeDetail(pbntId);
      setContents(prev => prev.map((c, i) => i === idx ? html : c));
    }
  };

  return (
    <BorderContents>
      {loading && <LoadingBar />}
      {items.map((item, i) => (
        <div key={item.pbntId} style={{ width: '100%' }}>
          <AccordionContainer onClick={() => handleClick(item.pbntId, i)}>
            <AccordionRow>
              <AccordionTitleBox>
                <AccordionTitle>{item.ttl}</AccordionTitle>
                <AccordionDate>{formatDate(item.frstRgstDttm)}</AccordionDate>
              </AccordionTitleBox>
              <ChevronIcon open={openStates[i]}>
                <ChevronSVG />
              </ChevronIcon>
            </AccordionRow>
          </AccordionContainer>
          {openStates[i] && (
            <ContentDetailBox>
              <div
                className="content comCont knotice"
                dangerouslySetInnerHTML={{ __html: contents[i] || '<p style="color:#67748e">내용을 불러오는 중...</p>' }}
              />
            </ContentDetailBox>
          )}
          <Divider />
        </div>
      ))}
      {page <= pageCount && <IntersectTarget ref={bottomRef} />}
    </BorderContents>
  );
}

/* ────── 사업공고 탭 (Navigate on click) ────── */
function BsntTabList() {
  const navigate = useNavigate();
  const [items, setItems] = useState<BsntItem[]>([]);
  const [page, setPage] = useState(1);
  const [pageCount, setPageCount] = useState(1);
  const [loading, setLoading] = useState(true);
  const bottomRef = useRef<HTMLDivElement>(null);

  const loadMore = useCallback(async () => {
    if (page > pageCount) return;
    try {
      const data = await fetchBsntList(page);
      const newItems = (data.list || []).map((it: BsntItem) => ({
        ...it,
        ttl: decode(it.ttl),
      }));
      setItems(prev => [...prev, ...newItems]);
      setPageCount(parseInt(String(data.pageCount)));
      setPage(p => p + 1);
    } finally {
      setLoading(false);
    }
  }, [page, pageCount]);

  useEffect(() => { loadMore(); }, []); // eslint-disable-line

  useEffect(() => {
    if (loading) return;
    if (page > pageCount) return;
    const el = bottomRef.current;
    if (!el) return;
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) loadMore();
    }, { threshold: 1 });
    obs.observe(el);
    return () => obs.disconnect();
  }, [bottomRef.current, loading, page, pageCount, loadMore]);

  return (
    <BorderContents>
      {loading && <LoadingBar />}
      <BsntBoardList>
        {items.map((item, i) => (
          <div key={item.pbntId} style={{ width: '100%' }}>
            <BsntAlignBox ref={i === items.length - 1 ? bottomRef : null}>
              <BsntLeftBox onClick={() => navigate(`/notice/view?num=${item.pbntId}`)}>
                <BsntTitleBox>
                  <BsntTitle>{item.ttl}</BsntTitle>
                  <BsntDate>{formatDate(item.frstRgstDttm)}</BsntDate>
                </BsntTitleBox>
              </BsntLeftBox>
            </BsntAlignBox>
            <Divider style={{ marginTop: '1.25rem' }} />
          </div>
        ))}
      </BsntBoardList>
      {page <= pageCount && <IntersectTarget ref={bottomRef} />}
    </BorderContents>
  );
}

