import styled from '@emotion/styled';
import { motion } from 'framer-motion';
import { useInView } from '../../hooks/useInView';
import { useEffect } from 'react';
import { kbankLogoUrl } from '../../data/mockData';

/* 원본 eH - TopPadding */
const TopPadding = styled.div`
  width: 100%;
  height: 1rem;
`;

/* 원본 eO - SectionCardContainer
   카드 없음: 배경·border-radius·box-shadow 전혀 없음
   페이지 그라디언트 배경이 그대로 비침 */
const Container = styled.div`
  display: flex;
  width: 100%;
  height: 19.0625rem;
  position: relative;
  justify-content: center;
  align-items: center;
  flex-direction: column;
  cursor: pointer;
`;

/* 원본 eV - ImageWrapper (로고 박스, 박스쉐도우만) */
const LogoBox = styled(motion.div)`
  width: 5rem;
  height: 5rem;
  position: relative;
  border-radius: 1rem;
  box-shadow: 12px 4px 24px 0px rgba(12, 9, 96, 0.24);
  overflow: hidden;

  img {
    width: 100%;
    height: 100%;
    object-fit: contain;
    border-radius: 1rem;
  }
`;

/* 원본 eq - TitleBox: position absolute bottom:0
   로고 아래, 컨테이너 하단에 고정 */
const TitleBox = styled(motion.div)`
  width: 13.0625rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.125rem;
  position: absolute;
  bottom: 0;
  text-align: center;
`;

const Title = styled.h2`
  font-size: clamp(1.5rem, 4vw, 2rem);
  font-weight: 700;
  color: #020616;
  line-height: 1.35;
  white-space: pre-line;
  text-align: center;
`;

/* 원본 eW - BottomPadding */
const BottomPadding = styled.div`
  width: 100%;
  height: 2rem;
`;

const SectionCard07 = ({ onView }: { onView?: () => void }) => {
  const { ref, inView } = useInView(0.3);

  useEffect(() => {
    if (inView) onView?.();
  }, [inView, onView]);

  return (
    <>
      <TopPadding />
      <Container
        ref={ref}
        onClick={() => window.open('https://www.kbanknow.com', '_blank')}
      >
        {/* 로고: y 0 → -50 으로 떠오름 */}
        <LogoBox
          initial={{ opacity: 0, y: 0 }}
          animate={inView ? { opacity: 1, y: -50 } : { opacity: 0, y: 0 }}
          transition={{ duration: 1 }}
        >
          <img src={kbankLogoUrl} alt="케이뱅크" />
        </LogoBox>

        {/* 텍스트: position absolute, bottom 0, 로고와 겹쳐서 올라옴 */}
        <TitleBox
          initial={{ opacity: 0, y: -10 }}
          animate={inView ? { opacity: 1, y: -40 } : { opacity: 0, y: -10 }}
          transition={{ duration: 1, delay: 0.05 }}
        >
          <Title>{'하나의 앱에서\n모두 경험하세요'}</Title>
        </TitleBox>
      </Container>
      <BottomPadding />
    </>
  );
};

export default SectionCard07;
